INSERT INTO formations (id_formation, titre, description, duree, prix, categorie, date_debut, places_disponibles, created_at, updated_at, deleted_at, benefices, id_pays) SELECT gen_random_uuid(), v.* FROM (VALUES ('Organisation administrative et comptable selon SYSCOHADA révisé', 'Formation sur les techniques de télémarketing pour améliorer la prospection et conclure des ventes par téléphone.', 5, 250000.00, 'entreprise', '2026-09-10', 30, '2026-01-14 12:37:32', '2026-02-18 23:44:04', NULL, E'--- OBJECTIFS ---\n• Maîtriser les techniques et stratégies du télémarketing\n• Améliorer la communication et la persuasion au téléphone\n• Gérer efficacement les objections et conclure les ventes\n• Optimiser l’organisation et le suivi des prospects\n• Utiliser les outils digitaux et CRM pour booster les performances\n\n--- OBJECTIFS DÉTAILLÉS ---\nMaîtriser les techniques du télémarketing, améliorer la communication et la persuasion, gérer les objections, optimiser l’organisation et le suivi des prospects et utiliser les outils digitaux et CRM pour accroître l’efficacité.\n\n--- PRÉREQUIS ---\nExpérience préalable en vente ou relation client souhaitée.\n\n--- CONTENU ---\nModule 1 : Introduction au télémarketing\nModule 2 : Préparation et organisation des appels\nModule 3 : Techniques de communication et persuasion\nModule 4 : Gestion des objections et négociation\nModule 5 : Suivi et fidélisation des clients\nModule 6 : Utilisation des outils numériques et CRM\nModule 7 : Simulation complète d’une campagne de télémarketing\n\n--- NIVEAU ---\nTous niveaux\n\n--- PUBLIC ---\nCommerciaux, télévendeurs, responsables marketing et commerciaux, chefs d’équipe.\n\n--- MÉTHODES ---\nPrésentations interactives, mises en situation, jeux de rôle, études de cas, simulations d’appels et exercices pratiques.\n\n--- SUPPORTS ---\nScripts d’appels, CRM, logiciels de gestion des contacts, supports PDF, modèles pratiques et simulations téléphoniques.\n\n--- CERTIFICATION ---\nAttestation de participation remise par ISD Groupe', 'ba52f30c-c061-41b8-b0f7-afa6eca6fa76')) AS v(titre, description, duree, prix, categorie, date_debut, places_disponibles, created_at, updated_at, deleted_at, benefices, id_pays) WHERE NOT EXISTS (SELECT 1 FROM formations f WHERE f.titre = v.titre AND f.date_debut = v.date_debut::date);
